const j = $json || {};
const ctx = j.ctx || {};
const parentAsset = j.parent_asset || {};
const parentSceneSeed = j.parent_scene_seed || {};
const parentSceneBlueprint = j.parent_scene_blueprint || {};
const plan = j.series_mutation_plan || {};
const variations = Array.isArray(plan.variations) ? plan.variations : [];
const now = new Date().toISOString();

if (!parentSceneSeed.scene_seed_id) throw new Error('TVPX__50: missing parent scene_seed_id.');

return variations.map((variation, idx) => {
  const childSeedId = \`tvpx_ss_\${fnv1a([
    ctx.trace_id,
    parentSceneSeed.scene_seed_id,
    variation.mutation_axis,
    variation.mutation_instruction,
    idx + 1,
  ].join('::'))}\`;

  const mutationId = \`tvpx_mut_\${fnv1a(childSeedId + '::mutation')}\`;
  const lineageId = \`tvpx_lin_\${fnv1a(childSeedId + '::lineage')}\`;

  const childSceneSeed = {
    scene_seed_id: childSeedId,
    trace_id: String(ctx.trace_id || '').trim(),
    crawl_run_id: String(parentSceneSeed.crawl_run_id || '').trim(),
    origin_type: 'telegram_series',
    source_id: String(parentSceneSeed.source_id || '').trim(),
    parent_scene_seed_id: String(parentSceneSeed.scene_seed_id || '').trim(),
    root_scene_seed_id: String(parentSceneSeed.root_scene_seed_id || parentSceneSeed.scene_seed_id || '').trim(),
    seed_fragment_ids_json: String(parentSceneSeed.seed_fragment_ids_json || '[]'),
    archetype_id: String(parentSceneSeed.archetype_id || '').trim(),
    subject_mode: String(parentSceneSeed.subject_mode || '').trim(),
    scene_kernel: String(variation.child_scene_kernel || parentSceneSeed.scene_kernel || '').trim(),
    concept_thesis: String(parentSceneSeed.concept_thesis || '').trim(),
    symbolic_tension: String(parentSceneSeed.symbolic_tension || '').trim(),
    material_anchor: String(parentSceneSeed.material_anchor || '').trim(),
    spatial_directive: String(variation.child_spatial_directive || parentSceneSeed.spatial_directive || '').trim(),
    palette_directive: String(variation.child_palette_directive || parentSceneSeed.palette_directive || '').trim(),
    texture_directive: String(variation.child_texture_directive || parentSceneSeed.texture_directive || '').trim(),
    dominant_subject: String(parentSceneSeed.dominant_subject || '').trim(),
    setting_family: String(parentSceneSeed.setting_family || '').trim(),
    ceremonial_logic: String(parentSceneSeed.ceremonial_logic || '').trim(),
    surreal_pressure: String(parentSceneSeed.surreal_pressure || '').trim(),
    negative_space_note: String(parentSceneSeed.negative_space_note || '').trim(),
    omission_notes: String(parentSceneSeed.omission_notes || '').trim(),
    forbidden_excess_json: String(parentSceneSeed.forbidden_excess_json || '[]'),
    render_budget_json: String(parentSceneSeed.render_budget_json || '{}'),
    quality_score: Number(parentSceneSeed.quality_score || 0),
    brand_fit_score: Number(parentSceneSeed.brand_fit_score || 0),
    reference_alignment_score: Number(parentSceneSeed.reference_alignment_score || 0),
    state: 'ready',
    lock_owner: '',
    lock_expires_at: null,
    used_count: 0,
    last_used_at: null,
    rejection_reason: '',
    created_at: now,
    updated_at: now,
  };

  return {
    json: {
      ctx: {
        ...ctx,
        asset_family_id: String(parentAsset.asset_family_id || ctx.asset_family_id || '').trim() || null,
      },
      tg: j.tg,
      child_scene_seed: childSceneSeed,
      mutation: {
        mutation_id: mutationId,
        parent_asset_id: String(parentAsset.asset_id || '').trim(),
        parent_render_candidate_id: String(parentAsset.render_candidate_id || '').trim(),
        parent_scene_seed_id: String(parentSceneSeed.scene_seed_id || '').trim(),
        parent_scene_blueprint_id: String(parentSceneBlueprint.scene_blueprint_id || '').trim(),
        child_scene_seed_id: childSeedId,
        mutation_axis: String(variation.mutation_axis || '').trim(),
        mutation_instruction: String(variation.mutation_instruction || '').trim(),
        status: 'planned',
        created_at: now,
        updated_at: now,
      },
      lineage: {
        lineage_id: lineageId,
        series_group_id: \`tvpx_series_\${fnv1a(parentSceneSeed.scene_seed_id + '::series')}\`,
        root_asset_id: String(parentAsset.root_asset_id || parentAsset.asset_id || '').trim(),
        parent_asset_id: String(parentAsset.asset_id || '').trim(),
        child_asset_id: null,
        parent_concept_id: String(parentSceneSeed.scene_seed_id || '').trim(),
        child_concept_id: childSeedId,
        parent_scene_seed_id: String(parentSceneSeed.scene_seed_id || '').trim(),
        child_scene_seed_id: childSeedId,
        parent_render_candidate_id: String(parentAsset.render_candidate_id || '').trim(),
        child_render_candidate_id: null,
        variation_index: idx + 1,
        variation_instruction: String(variation.mutation_instruction || '').trim(),
        continuity_rules_json: JSON.stringify({
          preserve_archetype: true,
          preserve_blueprint_family: true,
        }),
        created_at: now,
      },
    },
  };
});

const base = $items('Assemble Parent Image DNA Packet')[0]?.json || {};
const rows = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length);
const existing = rows.find(r => String(r.asset_id || '').trim()) || null;
return [{ json: { ...base, existing_bw_asset: existing } }];

const base = $items('Reattach B W Lookup')[0]?.json || {};
const existing = base.existing_bw_asset || {};
const binKeys = $binary ? Object.keys($binary) : [];
if (!binKeys.length) throw new Error('TVPX__50: no binary downloaded for existing B&W asset.');
const firstKey = binKeys[0];

function previewName(assetId) {
  const baseName = String(assetId || 'tvpx_bw_preview').replace(/\.[^.]+$/, '');
  return baseName + '_telegram_preview.jpg';
}

return [{
  json: {
    ctx: base.ctx,
    concept_id: String(existing.concept_id || base.parent_scene_seed?.scene_seed_id || '').trim(),
    scene_seed_id: String(existing.scene_seed_id || base.parent_scene_seed?.scene_seed_id || '').trim(),
    scene_blueprint_id: String(existing.scene_blueprint_id || base.parent_scene_blueprint?.scene_blueprint_id || '').trim(),
    archetype_id: String(existing.archetype_id || base.parent_archetype?.archetype_id || '').trim(),
    render_candidate_id: String(existing.render_candidate_id || '').trim(),
    blueprint_label: String(existing.blueprint_label || base.parent_scene_blueprint?.blueprint_label || '').trim(),
    asset_id: String(existing.asset_id || '').trim(),
    asset_family_id: String(existing.asset_family_id || base.parent_asset?.asset_family_id || '').trim() || null,
    assets: {
      bw: {
        drive_view_url: String(existing.drive_view_url || '').trim(),
        drive_download_url: String(existing.drive_download_url || '').trim(),
        provider_image_url: String(existing.provider_image_url || '').trim(),
      },
    },
    preview_filename: previewName(existing.asset_id),
  },
  binary: {
    image: $binary[firstKey],
  },
}];

const base = $items('Prepare Existing B W Telegram Packet')[0]?.json || {};
const resp = $json || {};
const msgId = resp.message_id || resp.result?.message_id || resp.data?.message_id;
return [{ json: { ...base, telegram: { bw_message_id: msgId ? Number(msgId) : null } } }];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const parentAsset = j.parent_asset || {};
const parentSceneSeed = j.parent_scene_seed || {};
const parentSceneBlueprint = j.parent_scene_blueprint || {};
const parentArchetype = j.parent_archetype || {};
const bwInstruction = String(j.bw_request?.instruction || '').trim();
const fallbackAssetId = \`tvpx_as_\${fnv1a(String(parentAsset.asset_id || parentSceneSeed.scene_seed_id || j.ctx?.trace_id || '') + '::bw')}\`;
const assetId = String(parentAsset.asset_id || '').trim().replace(/_(color|bw)$/i, '_bw') || fallbackAssetId;

const prompt = [
  'Photoreal black and white fine-art photograph, real-life camera image, not CGI or illustration.',
  'Archetype family: ' + String(parentArchetype.archetype_name || parentArchetype.archetype_id || '').trim() + '.',
  'Scene kernel: ' + String(parentSceneSeed.scene_kernel || '').trim() + '.',
  'Blueprint emphasis: ' + String(parentSceneBlueprint.candidate_prompt_core || parentSceneBlueprint.blueprint_label || '').trim() + '.',
  'Preserve staged inevitability, negative space as pressure, tactile material truth, and believable lens behavior.',
  'If a person is present, keep natural skin texture, realistic eyes, hands, posture, wardrobe, age detail, and unretouched human asymmetry.',
  'Use rich tonal separation, filmic shadow rolloff, real grain logic, and physically plausible monochrome light.',
  bwInstruction,
].filter(Boolean).join(' ');

const negative = 'cgi, 3d render, illustration, painterly brushstrokes, cartoon stylization, plastic skin, waxy skin, smooth skin, airbrushed skin, beauty retouching, uncanny eyes, bad hands, extra fingers, duplicate limbs, deformed anatomy, fake grain, glossy synthetic surfaces, text, watermark, logo';

return [{
  json: {
    ctx: j.ctx,
    concept_id: String(parentSceneSeed.scene_seed_id || '').trim(),
    scene_seed_id: String(parentSceneSeed.scene_seed_id || '').trim(),
    scene_blueprint_id: String(parentSceneBlueprint.scene_blueprint_id || '').trim(),
    archetype_id: String(parentArchetype.archetype_id || parentSceneSeed.archetype_id || '').trim(),
    blueprint_label: String(parentSceneBlueprint.blueprint_label || '').trim(),
    asset_id: assetId,
    asset_family_id: String(parentAsset.asset_family_id || j.reply_index?.asset_family_id || '').trim() || null,
    render_variant: 'bw',
    prompt,
    negative_prompt: negative,
    provider_controls: {
      image_size: '1024x1536',
      background: 'opaque',
      quality: 'high',
      output_format: 'png',
      num_images: 1,
    },
  },
}];

const render = $json || {};
const base = $items('Build B W Render Request')[0]?.json || {};
const imageUrl = String(render.image_url || '').trim();
if (!imageUrl) throw new Error('TVPX__50: B&W render returned no image_url.');

return [{
  json: {
    ctx: base.ctx,
    concept_id: String(base.scene_seed_id || base.concept_id || '').trim(),
    scene_seed_id: String(base.scene_seed_id || '').trim(),
    scene_blueprint_id: String(base.scene_blueprint_id || '').trim(),
    archetype_id: String(base.archetype_id || '').trim(),
    render_candidate_id: String(render.render_candidate_id || '').trim(),
    blueprint_label: String(base.blueprint_label || '').trim(),
    asset_id: String(base.asset_id || '').trim(),
    asset_family_id: String(base.asset_family_id || '').trim() || null,
    family: {
      bw: {
        image_url: imageUrl,
        provider_image_url: imageUrl,
        output_format: String(render.output_format || base.provider_controls?.output_format || 'png'),
        render_candidate_id: String(render.render_candidate_id || '').trim(),
      },
    },
  },
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const base = $items('Assemble Parent Image DNA Packet')[0]?.json || {};
const parentAsset = base.parent_asset || {};
const parentSceneSeed = base.parent_scene_seed || {};
const parentSceneBlueprint = base.parent_scene_blueprint || {};
const parentArchetype = base.parent_archetype || {};
const rows = $input.all().map((i) => i.json).filter((row) => row && Object.keys(row).length && String(row.asset_id || '').trim());
const priority = { prepared: 5, queued: 4, processing: 3, failed: 2, timed_out: 1, cancelled: 0 };
rows.sort((a, b) => (priority[String(b.state || '').trim().toLowerCase()] || -1) - (priority[String(a.state || '').trim().toLowerCase()] || -1));
const existing = rows[0] || null;
const state = String(existing?.state || '').trim().toLowerCase();
const shouldUpsert = !existing || ['failed', 'timed_out', 'cancelled'].includes(state);
const shouldPrepare = !existing || state === 'queued' || ['failed', 'timed_out', 'cancelled'].includes(state);
const stillUrl = String(parentAsset.drive_view_url || parentAsset.drive_download_url || parentAsset.provider_image_url || '').trim();
if (!stillUrl) throw new Error('TVPX__50: parent asset has no still image URL for motion prep.');

const videoSeedId = String(existing?.video_seed_id || \`tvpx_vid_\${fnv1a(String(parentAsset.asset_id || parentSceneSeed.scene_seed_id || base.ctx?.trace_id || ''))}\`);
let ackText = 'The Velvet Paradox — motion prep queued for this image.';
if (state === 'prepared') ackText = 'The Velvet Paradox — motion prep already exists for this image.';
else if (state === 'processing') ackText = 'The Velvet Paradox — motion prep is already in progress for this image.';
else if (state === 'queued') ackText = 'The Velvet Paradox — motion prep was already queued; refreshing the prep run now.';
else if (['failed', 'timed_out', 'cancelled'].includes(state)) ackText = 'The Velvet Paradox — motion prep was stale, so it has been re-queued.';

return [{
  json: {
    ...base,
    existing_video_seed: existing,
    video_plan: {
      state,
      should_upsert: shouldUpsert,
      should_prepare: shouldPrepare,
      ack_text: ackText,
      video_seed: {
        video_seed_id: videoSeedId,
        asset_id: String(parentAsset.asset_id || '').trim(),
        concept_id: String(parentSceneSeed.scene_seed_id || '').trim(),
        scene_seed_id: String(parentSceneSeed.scene_seed_id || '').trim(),
        scene_blueprint_id: String(parentSceneBlueprint.scene_blueprint_id || '').trim(),
        archetype_id: String(parentArchetype.archetype_id || parentSceneSeed.archetype_id || '').trim(),
        provider_target: 'fal_video',
        still_image_drive_url: stillUrl,
        motion_prompt: String(base.video_request?.instruction || '').trim(),
        camera_motion_profile: '',
        duration_hint: '5-7s',
        aspect_ratio: '4:5',
        state: 'queued',
        created_at: new Date().toISOString(),
      },
    },
  },
}];

const j = $json || {};
const child = j.child_scene_seed || {};
const ctx = j.ctx || {};
const sceneSeedId = String(child.scene_seed_id || j.scene_seed_id || '').trim();
if (!sceneSeedId) throw new Error('TVPX__50: child scene_seed_id missing before image generation dispatch.');

return [{
  json: {
    ...j,
    ctx,
    concept_id: sceneSeedId,
    scene_seed_id: sceneSeedId,
    asset_family_id: String(ctx.asset_family_id || j.asset_family_id || '').trim() || null,
  },
}];

const base = $items('Reattach After Reply Lookup')[0]?.json || {};
const parentAsset = $items('Get Parent Asset')[0]?.json || {};
const parentSceneSeed = $items('Get Parent Scene Seed')[0]?.json || {};
const parentSceneBlueprint = $items('Get Parent Scene Blueprint')[0]?.json || {};
const parentArchetype = $items('Get Parent Archetype')[0]?.json || {};

if (!parentAsset.asset_id) throw new Error('TVPX__50: parent asset not found.');
if (!parentSceneSeed.scene_seed_id) throw new Error('TVPX__50: parent scene seed not found.');
if (!parentSceneBlueprint.scene_blueprint_id) throw new Error('TVPX__50: parent scene blueprint not found.');
if (!parentArchetype.archetype_id) throw new Error('TVPX__50: parent archetype not found.');

return [{
  json: {
    ctx: base.ctx,
    tg: base.tg,
    reply_action: base.reply_action,
    series_request: base.series_request,
    bw_request: base.bw_request,
    video_request: base.video_request,
    series_command: base.series_request?.instruction || base.tg?.text || '',
    reply_index: base.reply_index,
    parent_asset: parentAsset,
    parent_scene_seed: parentSceneSeed,
    parent_scene_blueprint: parentSceneBlueprint,
    parent_archetype: parentArchetype,
  },
}];

const base = $items('Build Child Scene Seeds', 0, 0)[$itemIndex]?.json || $items('Build Child Scene Seeds')[$itemIndex]?.json || null;
if (!base) throw new Error('TVPX__50: missing child scene seed packet.');
return [{ json: base }];
